def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length
  val directions = Array((0, 1), (1, 0)) // right and down
  val heap = mutable.PriorityQueue.empty[(Long, Int, Int, Int)](
